import java.util.*;

class Solution {

    // Function to calculate Longest Common Subsequence
    public int lcs(String s1, String s2) {

        // Get sizes of strings
        int n = s1.length();
        int m = s2.length();

        // Create dp array
        int[][] dp = new int[n + 1][m + 1];

        // Fill dp array
        for (int ind1 = 1; ind1 <= n; ind1++) {
            for (int ind2 = 1; ind2 <= m; ind2++) {

                // If characters match
                if (s1.charAt(ind1 - 1) == s2.charAt(ind2 - 1)) {
                    dp[ind1][ind2] = 
                        1 + dp[ind1 - 1][ind2 - 1];
                }

                // If they don't match
                else {
                    dp[ind1][ind2] = 
                        Math.max(dp[ind1 - 1][ind2], 
                                 dp[ind1][ind2 - 1]);
                }
            }
        }

        // Return bottom-right value
        return dp[n][m];
    }

    // Function to calculate LPS
    public int longestPalindromeSubsequence(String s) {

        // Reverse string
        String t = new StringBuilder(s).reverse().toString();

        // LCS of s and reverse
        return lcs(s, t);
    }

    // Function to calculate minimum insertions
    public int minInsertion(String s) {

        // Get length
        int n = s.length();

        // Get LPS length
        int k = longestPalindromeSubsequence(s);

        // Return answer
        return n - k;
    }
}

public class Main {
    public static void main(String[] args) {

        // Create object
        Solution sol = new Solution();

        // Input string
        Scanner sc = new Scanner(System.in);
        String s = sc.next();

        // Print result
        System.out.println(sol.minInsertion(s));
    }
}

