class Solution {

    // Function to calculate LCS
    lcs(s1, s2) {

        // Get lengths
        const n = s1.length;
        const m = s2.length;

        // Create dp array
        const dp = Array.from({ length: n + 1 }, () => 
                   Array(m + 1).fill(0));

        // Fill dp array
        for (let ind1 = 1; ind1 <= n; ind1++) {
            for (let ind2 = 1; ind2 <= m; ind2++) {

                // If characters match
                if (s1[ind1 - 1] === s2[ind2 - 1]) {
                    dp[ind1][ind2] = 
                        1 + dp[ind1 - 1][ind2 - 1];
                }

                // If not
                else {
                    dp[ind1][ind2] = Math.max(
                        dp[ind1 - 1][ind2], 
                        dp[ind1][ind2 - 1]
                    );
                }
            }
        }

        // Return final result
        return dp[n][m];
    }

    // Function to get LPS
    longestPalindromeSubsequence(s) {

        // Reverse string
        const t = s.split('').reverse().join('');

        // Return LCS of s and reverse
        return this.lcs(s, t);
    }

    // Function to get min insertions
    minInsertion(s) {

        // Get LPS
        const k = this.longestPalindromeSubsequence(s);

        // Return result
        return s.length - k;
    }
}

